@* CheckoutWizard.razor — manages active step and holds the Order state *@

<div class="checkout-wizard">
    <h2>Checkout</h2>

    @if (step == 1)
    {
        <ShippingStep Shipping="order.Shipping"
                      ShippingChanged="OnShippingChanged"
                      OnNext="GoToPayment" />
    }
    else
    {
        <PaymentStep Payment="order.Payment"
                     PaymentChanged="OnPaymentChanged"
                     OnBack="GoToShipping"
                     OnPlaceOrder="PlaceOrder" />
    }
</div>

@code {
    /// <summary>Raised when the user completes the order.</summary>
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private Order order = new();
    private int step = 1;

    private void OnShippingChanged(ShippingInfo shipping)
    {
        order.Shipping = shipping;
    }

    private void OnPaymentChanged(PaymentInfo payment)
    {
        order.Payment = payment;
    }

    private void GoToPayment() => step = 2;

    private void GoToShipping() => step = 1;

    private async Task PlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(order);
    }
}

@* ShippingStep.razor — collects shipping address fields *@

<fieldset>
    <legend>Shipping Information</legend>

    <div class="form-group">
        <label for="name">Name</label>
        <input id="name" value="@Shipping.Name"
               @oninput="e => Update(s => s.Name = e.Value?.ToString() ?? string.Empty)" />
    </div>

    <div class="form-group">
        <label for="address">Address</label>
        <input id="address" value="@Shipping.Address"
               @oninput="e => Update(s => s.Address = e.Value?.ToString() ?? string.Empty)" />
    </div>

    <div class="form-group">
        <label for="city">City</label>
        <input id="city" value="@Shipping.City"
               @oninput="e => Update(s => s.City = e.Value?.ToString() ?? string.Empty)" />
    </div>

    <div class="form-group">
        <label for="zip">Zip Code</label>
        <input id="zip" value="@Shipping.ZipCode"
               @oninput="e => Update(s => s.ZipCode = e.Value?.ToString() ?? string.Empty)" />
    </div>

    @if (!CanProceed)
    {
        <p class="validation-message">Name and Address are required.</p>
    }

    <button disabled="@(!CanProceed)" @onclick="OnNext">Next</button>
</fieldset>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback<ShippingInfo> ShippingChanged { get; set; }

    [Parameter]
    public EventCallback OnNext { get; set; }

    private bool CanProceed =>
        !string.IsNullOrWhiteSpace(Shipping.Name) &&
        !string.IsNullOrWhiteSpace(Shipping.Address);

    private async Task Update(Action<ShippingInfo> apply)
    {
        apply(Shipping);
        await ShippingChanged.InvokeAsync(Shipping);
    }
}

